$ErrorActionPreference='Stop'
$headers = @{ 'Authorization' = "Bearer $env:NOTION_TOKEN"; 'Notion-Version' = '2025-09-03'; 'Content-Type' = 'application/json; charset=utf-8' }
function RichText($text){
  if ([string]::IsNullOrEmpty([string]$text)) { return @() }
  return ,@{ type='text'; text=@{ content=[string]$text } }
}
function Cells([string[]]$values){
  $out = @()
  foreach($v in $values){ $out += ,(RichText $v) }
  return ,$out
}
function Add-TableRow($tableId, [string[]]$values){
  $bodyObj = @{ children = @(@{ object='block'; type='table_row'; table_row=@{ cells = (Cells $values) } }) }
  $body = $bodyObj | ConvertTo-Json -Depth 20
  Invoke-RestMethod -Method Patch -Uri "https://api.notion.com/v1/blocks/$tableId/children" -Headers $headers -Body ([System.Text.Encoding]::UTF8.GetBytes($body)) | Out-Null
}
function Archive-Block($blockId){
  $body = @{ archived = $true } | ConvertTo-Json -Compress
  Invoke-RestMethod -Method Patch -Uri "https://api.notion.com/v1/blocks/$blockId" -Headers $headers -Body ([System.Text.Encoding]::UTF8.GetBytes($body)) | Out-Null
}
